func (o *Connection) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "ConnectionAccesses":
		rels, ok := retrieved.(ConnectionAccessSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.ConnectionAccesses = rels

		return nil
	case "User":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.User = rel

		return nil
	case "SchemaChunks":
		rels, ok := retrieved.(SchemaChunkSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.SchemaChunks = rels

		return nil
	case "SchemaSnapshots":
		rels, ok := retrieved.(SchemaSnapshotSlice)
		if !ok {
			return fmt.Errorf("connection cannot load %T as %q", retrieved, name)
		}

		o.R.SchemaSnapshots = rels

		return nil
	default:
		return fmt.Errorf("connection has no relationship %q", name)
	}
}

type connectionPreloader struct {
	User func(...psql.PreloadOption) psql.Preloader
}

func buildConnectionPreloader() connectionPreloader {
	return connectionPreloader{
		User: func(opts ...psql.PreloadOption) psql.Preloader {
			return psql.Preload[*User, UserSlice](psql.PreloadRel{
				Name: "User",
				Sides: []psql.PreloadSide{
					{
						From:        Connections,
						To:          Users,
						FromColumns: []string{"user_id"},
						ToColumns:   []string{"id"},
					},
				},
			}, Users.Columns.Names(), opts...)
		},
	}
}

type connectionThenLoader[Q orm.Loadable] struct {
	ConnectionAccesses func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	User               func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SchemaChunks       func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
	SchemaSnapshots    func(...bob.Mod[*dialect.SelectQuery]) orm.Loader[Q]
}

func buildConnectionThenLoader[Q orm.Loadable]() connectionThenLoader[Q] {
	type ConnectionAccessesLoadInterface interface {
		LoadConnectionAccesses(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type UserLoadInterface interface {
		LoadUser(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SchemaChunksLoadInterface interface {
		LoadSchemaChunks(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}
	type SchemaSnapshotsLoadInterface interface {
		LoadSchemaSnapshots(context.Context, bob.Executor, ...bob.Mod[*dialect.SelectQuery]) error
	}

	return connectionThenLoader[Q]{
		ConnectionAccesses: thenLoadBuilder[Q](
			"ConnectionAccesses",
			func(ctx context.Context, exec bob.Executor, retrieved ConnectionAccessesLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadConnectionAccesses(ctx, exec, mods...)
			},
		),
		User: thenLoadBuilder[Q](
			"User",
			func(ctx context.Context, exec bob.Executor, retrieved UserLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadUser(ctx, exec, mods...)
			},
		),
		SchemaChunks: thenLoadBuilder[Q](
			"SchemaChunks",
			func(ctx context.Context, exec bob.Executor, retrieved SchemaChunksLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadSchemaChunks(ctx, exec, mods...)
			},
		),
		SchemaSnapshots: thenLoadBuilder[Q](
			"SchemaSnapshots",
			func(ctx context.Context, exec bob.Executor, retrieved SchemaSnapshotsLoadInterface, mods ...bob.Mod[*dialect.SelectQuery]) error {
				return retrieved.LoadSchemaSnapshots(ctx, exec, mods...)
			},
		),
	}
}

// LoadConnectionAccesses loads the connection's ConnectionAccesses into the .R struct
func (o *Connection) LoadConnectionAccesses(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.ConnectionAccesses = nil

	related, err := o.ConnectionAccesses(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	o.R.ConnectionAccesses = related
	return nil
}

// LoadConnectionAccesses loads the connection's ConnectionAccesses into the .R struct
func (os ConnectionSlice) LoadConnectionAccesses(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	connectionAccesses, err := os.ConnectionAccesses(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.ConnectionAccesses = nil
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range connectionAccesses {

			if !(o.ID == rel.ConnectionID) {
				continue
			}

			o.R.ConnectionAccesses = append(o.R.ConnectionAccesses, rel)
		}
	}

	return nil
}

// LoadUser loads the connection's User into the .R struct
func (o *Connection) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.User = nil

	related, err := o.User(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	o.R.User = related
	return nil
}

// LoadUser loads the connection's User into the .R struct
func (os ConnectionSlice) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.User(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range users {

			if !(o.UserID == rel.ID) {
				continue
			}

			o.R.User = rel
			break
		}
	}

	return nil
}

